const pipeline = (x) => x();

const importers = [
  async (path) => {
    if (!/^\.[\\/](?:src[\\/]shared[\\/]components(?:[\\/](?!\.)(?:(?:(?!(?:^|[\\/])\.).)*?)[\\/]|[\\/]|$)(?!\.)(?=.)[^\\/]*?\.stories\.(ts|tsx|mdx))$/.exec(path)) {
      return;
    }
  
    const pathRemainder = path.substring(24);
    return import(
      /* webpackChunkName: "[request]" */
      /* webpackInclude: /(?:[\\/]src[\\/]shared[\\/]components(?:[\\/](?!\.)(?:(?:(?!(?:^|[\\/])\.).)*?)[\\/]|[\\/]|$)(?!\.)(?=.)[^\\/]*?\.stories\.(ts|tsx|mdx))$/ */
      './src/shared/components/' + pathRemainder
    );
  }
  
];

export async function importFn(path) {
  for (let i = 0; i < importers.length; i++) {
    const moduleExports = await pipeline(() => importers[i](path));
    if (moduleExports) {
      return moduleExports;
    }
  }
}